        // Check if business line is valid
        boolean isValidBusiness = Arrays.asList(businessOrder).contains(businessLine[i]);
        // Check if coupon is active
        boolean isActive = isActive[i];

        if (isValidCode && isValidBusiness && isActive) {
            validCoupons.add(code[i]);
        }
    }

    // Sort the valid coupons first by business line order, then by code lexicographically
    validCoupons.sort(new Comparator<String>() {
        @Override
        public int compare(String a, String b) {
            // Find the index of the business line in the order
